import { FormatFn } from '../../src/sqlFormatter.js';

export default function supportsPipeOperator(format: FormatFn) {
  it('formats a basic pipe query', () => {
    expect(format(`FROM users |> WHERE age > 21 |> SELECT name, age |> LIMIT 10;`)).toBe(dedent`
      FROM
        users
      |> WHERE
        age > 21
      |> SELECT
        name,
        age
      |> LIMIT 10;
    `);
  });

  it('tokenizes |> as a distinct operator (not bitwise-or followed by >)', () => {
    // A plain bitwise-or should still be handled as before
    expect(format(`SELECT a | b FROM t`)).toBe(dedent`
      SELECT
        a | b
      FROM
        t
    `);
  });

  it('formats one-line pipe clauses on the keyword line', () => {
    expect(format(`FROM t |> JOIN other ON t.id = other.id |> AS renamed |> LIMIT 5`)).toBe(dedent`
      FROM
        t
      |> JOIN other ON t.id = other.id
      |> AS renamed
      |> LIMIT 5
    `);
  });

  it('formats indented pipe clauses with body on the next line', () => {
    expect(format(`FROM t |> EXTEND a + b AS total |> SET x = 1 |> DROP col1, col2 |> ORDER BY x`))
      .toBe(dedent`
      FROM
        t
      |> EXTEND
        a + b AS total
      |> SET
        x = 1
      |> DROP
        col1,
        col2
      |> ORDER BY
        x
    `);
  });

  it('formats AGGREGATE with a nested GROUP BY sub-clause', () => {
    expect(format(`FROM t |> AGGREGATE count(*) AS c, sum(x) GROUP BY category, region`)).toBe(dedent`
      FROM
        t
      |> AGGREGATE
        count(*) AS c,
        sum(x)
        GROUP BY
          category,
          region
    `);
  });

  it('formats AGGREGATE without a GROUP BY sub-clause', () => {
    expect(format(`FROM t |> AGGREGATE count(*) AS total`)).toBe(dedent`
      FROM
        t
      |> AGGREGATE
        count(*) AS total
    `);
  });

  it('formats a pipe query nested inside a parenthesized subquery', () => {
    expect(format(`SELECT * FROM (FROM t |> WHERE x > 1 |> SELECT y) AS sub;`)).toBe(dedent`
      SELECT
        *
      FROM
        (
          FROM
            t
          |> WHERE
            x > 1
          |> SELECT
            y
        ) AS sub;
    `);
  });

  it('honors keywordCase for pipe keywords, including pipe-exclusive ones', () => {
    expect(
      format(`FROM t |> WHERE x |> AGGREGATE count(*) GROUP BY y |> LIMIT 5`, {
        keywordCase: 'lower',
      })
    ).toBe(dedent`
      from
        t
      |> where
        x
      |> aggregate
        count(*)
        group by
          y
      |> limit 5
    `);
  });

  it('attaches a trailing semicolon after the final pipe step', () => {
    expect(format(`FROM t |> WHERE x |> LIMIT 5;`)).toBe(dedent`
      FROM
        t
      |> WHERE
        x
      |> LIMIT 5;
    `);
  });

  it('formats traditional queries unchanged alongside pipe queries', () => {
    expect(format(`SELECT a FROM t; FROM t |> WHERE x;`)).toBe(dedent`
      SELECT
        a
      FROM
        t;

      FROM
        t
      |> WHERE
        x;
    `);
  });
}
